internal final class ETGAgreementTrackingReportUIBuilder extends SrsReportDataContractUIBuilder
{
    DialogField dlgFromDate, dlgCommodity, dlgSubCommodity, dlgVertical, dlgSubVertical, dlgQty, dlgPerDate;
    ETGAgreementTrackingReportContract contract;

}

Method.Source:
public void build()
{
    contract = this.dataContractObject();

    dlgFromDate      = this. addDialogField(methodStr(ETGDeliveryScheduleReportContract, parmFromDate), contract);
    dlgPerDate       = this.addDialogField(methodStr(ETGAgreementTrackingReportContract, parmPerDate), contract);
    dlgVertical      = this.addDialogField(methodStr(ETGAgreementTrackingReportContract, parmETGVertical),      contract);
    dlgSubVertical   = this.addDialogField(methodStr(ETGAgreementTrackingReportContract, parmETGSubVertical),   contract);
    dlgCommodity     = this.addDialogField(methodStr(ETGAgreementTrackingReportContract, parmETGCommodity),     contract);
    dlgSubCommodity  = this.addDialogField(methodStr(ETGAgreementTrackingReportContract, parmETGSubCommodity),  contract);
    dlgQty           = this.addDialogField(methodStr(ETGAgreementTrackingReportContract, parmQty), contract);
}

public void postBuild()
{
    super();
    dlgFromDate     = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETGAgreementTrackingReportContract, parmFromDate));
    dlgPerDate      = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETGAgreementTrackingReportContract, parmPerDate));
    dlgVertical     = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETGAgreementTrackingReportContract, parmETGVertical));
    dlgSubVertical  = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETGAgreementTrackingReportContract, parmETGSubVertical));
    dlgCommodity    = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETGAgreementTrackingReportContract, parmETGCommodity));
    dlgSubCommodity = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETGAgreementTrackingReportContract, parmETGSubCommodity));

    dlgVertical.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGAgreementTrackingReportUIBuilder, lookupETGVertical), this);
    dlgSubVertical.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGAgreementTrackingReportUIBuilder, lookupETGSubVertical), this);
    dlgCommodity.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGAgreementTrackingReportUIBuilder, lookupETGCommodity), this);
    dlgSubCommodity.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGAgreementTrackingReportUIBuilder, lookupETGSubCommodity), this);

}

public void lookupETGCommodity(FormStringControl _formStringControl)
{
    SysTableLookup sysTableLookup = SysTableLookup::newParameters(tableNum(DimensionAttributeValue), _formStringControl);

    Query query = new Query();
    QueryBuildDataSource qbds = query.addDataSource(tableNum(DimensionAttributeValue));
    QueryBuildRange qbr = qbds.addRange(fieldNum(DimensionAttributeValue, DimensionAttribute));

    DimensionAttribute dimAttr = DimensionAttribute::findByName(ETGACFParameters::find().MainCommodity);
    qbr.value(queryValue(dimAttr.RecId));

    sysTableLookup.addLookupfield(fieldNum(DimensionAttributeValue, DisplayValue));
    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}

